code.C:
#include <stdio.h>
int getSingleElement(int arr[], int n) {
    int res = arr[0];
    for (int i = 1; i < n; i++) {
        res = res ^ arr[i];
    }
    return res;
}

int main() {
    int arr[] = {4, 1, 2, 1, 2};
    int n = sizeof(arr) / sizeof(arr[0]);
    printf("The single element is: %d\n", getSingleElement(arr, n));
    return 0;
}

code.C++:
#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
    int getSingleElement(vector<int>& arr) {
        int res = arr[0];
        for (int i = 1; i < arr.size(); i++) {
            res = res ^ arr[i];
        }
        return res;
    }
};

int main() {
    vector<int> arr = {4, 1, 2, 1, 2};
    Solution obj;
    int ans = obj.getSingleElement(arr);
    cout << "The single element is: " << ans << endl;
    return 0;
}

code.Java:
class Solution {
    public int getSingleElement(int[] arr) {
        int res = arr[0];
        for (int i = 1; i < arr.length; i++) {
            res = res ^ arr[i];
        }
        return res;
    }
}

public class Main {
    public static void main(String[] args) {
        int[] arr = {4, 1, 2, 1, 2};
        Solution obj = new Solution();
        int ans = obj.getSingleElement(arr);
        System.out.println("The single element is: " + ans);
    }
}

